import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/AdminDashboard.css';

function AdminDashboard() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [statistics, setStatistics] = useState({
    totalUsers: 0,
    activeSessions: 0,
    medicationRecords: 0,
    healthRecords: 0
  });
  const [recentUsers, setRecentUsers] = useState([]);
  const [modelPerformance, setModelPerformance] = useState({
    accuracy: 0,
    precision: 0,
    recall: 0,
    f1Score: 0
  });
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');

  // API URL
  const API_URL = 'http://localhost:5000/api';

  useEffect(() => {
    // Check if user is logged in and is admin
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    // Verify admin role
    verifyAdminRole(user_id);
    
    // Fetch admin dashboard data
    fetchDashboardData();
  }, [navigate]);

  const verifyAdminRole = async (userId) => {
    try {
      const response = await fetch(`${API_URL}/user-role/${userId}`);
      if (!response.ok) {
        throw new Error('Failed to verify admin role');
      }
      
      const data = await response.json();
      if (!data.role || data.role !== 'admin') {
        // Redirect non-admin users to regular dashboard
        navigate('/dashboard');
      }
    } catch (err) {
      console.error('Error verifying admin role:', err);
      setError('Failed to verify admin permissions');
      navigate('/dashboard');
    }
  };

  const fetchDashboardData = async () => {
    setIsLoading(true);
    try {
      // Fetch system statistics
      const statsResponse = await fetch(`${API_URL}/admin/statistics`);
      if (!statsResponse.ok) {
        throw new Error('Failed to fetch system statistics');
      }
      const statsData = await statsResponse.json();
      setStatistics(statsData);

      // Fetch recent users
      const usersResponse = await fetch(`${API_URL}/admin/recent-users`);
      if (!usersResponse.ok) {
        throw new Error('Failed to fetch recent users');
      }
      const usersData = await usersResponse.json();
      setRecentUsers(usersData.users);

      // Fetch model performance metrics
      const modelResponse = await fetch(`${API_URL}/admin/model-performance`);
      if (!modelResponse.ok) {
        throw new Error('Failed to fetch model performance');
      }
      const modelData = await modelResponse.json();
      setModelPerformance(modelData);

    } catch (err) {
      console.error('Error fetching dashboard data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  if (isLoading) {
    return (
      <div className="admin-dashboard-container">
        <div className="loading-indicator">
          <p>Loading admin dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`admin-dashboard-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring - Admin Dashboard</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="admin-content">
        {error && <div className="error-message">{error}</div>}
        
        <div className="admin-header">
          <h2>System Overview</h2>
          <button onClick={fetchDashboardData} className="refresh-button">
            Refresh Data
          </button>
        </div>

        <div className="stats-grid">
          <div className="stat-card">
            <h3>Total Users</h3>
            <p className="stat-value">{statistics.totalUsers}</p>
          </div>
          <div className="stat-card">
            <h3>Active Sessions</h3>
            <p className="stat-value">{statistics.activeSessions}</p>
          </div>
          <div className="stat-card">
            <h3>Medication Records</h3>
            <p className="stat-value">{statistics.medicationRecords}</p>
          </div>
          <div className="stat-card">
            <h3>Health Records</h3>
            <p className="stat-value">{statistics.healthRecords}</p>
          </div>
        </div>

        <div className="admin-section">
          <h2>Neural Network Performance</h2>
          <div className="model-performance">
            <div className="performance-metric">
              <h4>Accuracy</h4>
              <div className="metric-value">{(modelPerformance.accuracy * 100).toFixed(2)}%</div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{width: `${modelPerformance.accuracy * 100}%`}}
                ></div>
              </div>
            </div>
            <div className="performance-metric">
              <h4>Precision</h4>
              <div className="metric-value">{(modelPerformance.precision * 100).toFixed(2)}%</div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{width: `${modelPerformance.precision * 100}%`}}
                ></div>
              </div>
            </div>
            <div className="performance-metric">
              <h4>Recall</h4>
              <div className="metric-value">{(modelPerformance.recall * 100).toFixed(2)}%</div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{width: `${modelPerformance.recall * 100}%`}}
                ></div>
              </div>
            </div>
            <div className="performance-metric">
              <h4>F1 Score</h4>
              <div className="metric-value">{(modelPerformance.f1Score * 100).toFixed(2)}%</div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{width: `${modelPerformance.f1Score * 100}%`}}
                ></div>
              </div>
            </div>
          </div>
        </div>

        <div className="admin-section">
          <h2>Recent User Activity</h2>
          <table className="users-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Email</th>
                <th>Registration Date</th>
                <th>Last Login</th>
                <th>Records Count</th>
              </tr>
            </thead>
            <tbody>
              {recentUsers.map(user => (
                <tr key={user.id}>
                  <td>{user.id}</td>
                  <td>{user.email}</td>
                  <td>{new Date(user.created_at).toLocaleDateString()}</td>
                  <td>{user.last_login ? new Date(user.last_login).toLocaleString() : 'Never'}</td>
                  <td>{user.records_count}</td>
                </tr>
              ))}
              {recentUsers.length === 0 && (
                <tr>
                  <td colSpan="5" className="no-data">No user data available</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="admin-actions">
          <h2>Administrative Actions</h2>
          <div className="action-buttons">
            <button className="admin-button">
              Retrain Model
            </button>
            <button className="admin-button">
              Download System Logs
            </button>
            <button className="admin-button">
              User Management
            </button>
            <button className="admin-button">
              System Settings
            </button>
          </div>
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Admin Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/admin-dashboard')} className="active">
            Dashboard
          </button>
          <button onClick={() => navigate('/user-management')}>
            User Management
          </button>
          <button onClick={() => navigate('/model-analytics')}>
            Model Analytics
          </button>
          <button onClick={() => navigate('/system-logs')}>
            System Logs
          </button>
          <button onClick={() => navigate('/settings')}>
            Settings
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default AdminDashboard;
